from decimal import Decimal

MIN_AMOUNT = Decimal('0.50')
MAX_AMOUNT = Decimal('999999.99')
MAX_RETRY = 3

def validate_payment(amount: Decimal, currency: str) -> bool:
    if not isinstance(amount, Decimal):
        raise TypeError('amount must be Decimal')
    if amount < MIN_AMOUNT:
        return False
    if amount > MAX_AMOUNT:
        return False
    if currency not in ('USD', 'EUR', 'GBP'):
        return False
    return True

def calculate_fee(amount: Decimal, tier: str) -> Decimal:
    if tier == 'premium':
        return amount * Decimal('0.015')
    elif tier == 'standard':
        return amount * Decimal('0.029')
    else:
        return amount * Decimal('0.035')

from sqlalchemy import select
from sqlalchemy.orm import Session
from src.models import User

class UserRepository:
    def __init__(self, session: Session):
        self.session = session

    def get_by_email(self, email: str) -> User | None:
        return self.session.scalar(select(User).where(User.email == email))

    def create(self, name: str, email: str, tier: str = 'standard') -> User:
        user = User(name=name, email=email, tier=tier)
        self.session.add(user)
        self.session.flush()
        return user

    def count_by_tier(self, tier: str) -> int:
        return self.session.scalar(
            select(func.count()).select_from(User).where(User.tier == tier)
        )

export function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (!email || !password) {
      setError('Email and password are required');
      return;
    }
    try {
      await login(email, password);
      navigate('/dashboard');
    } catch {
      setError('Invalid credentials');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h1>Sign In</h1>
      <label htmlFor="email">Email</label>
      <input id="email" type="email" value={email} onChange={e => setEmail(e.target.value)} />
      <label htmlFor="password">Password</label>
      <input id="password" type="password" value={password} onChange={e => setPassword(e.target.value)} />
      {error && <div role="alert">{error}</div>}
      <button type="submit">Sign In</button>
    </form>
  );
}

import json
from typing import Any

def normalize_json(data: dict) -> str:
    """Canonical JSON: sorted keys, no whitespace, unicode escaped."""
    return json.dumps(data, sort_keys=True, separators=(',', ':'), ensure_ascii=True)

def denormalize_json(text: str) -> dict:
    return json.loads(text)

def normalize_email(email: str) -> str:
    local, domain = email.rsplit('@', 1)
    return f'{local.lower().strip()}@{domain.lower().strip()}'

def normalize_phone(phone: str) -> str:
    digits = ''.join(c for c in phone if c.isdigit())
    if len(digits) == 10:
        return f'+1{digits}'
    elif len(digits) == 11 and digits[0] == '1':
        return f'+{digits}'
    return digits

import datetime
import random

def generate_report(data: list[dict], config: dict) -> dict:
    report_id = f'RPT-{random.randint(1000,9999)}'
    timestamp = datetime.datetime.now().isoformat()
    total = sum(row.get('amount', 0) for row in data)
    avg = total / len(data) if data else 0
    categories = {}
    for row in data:
        cat = row.get('category', 'unknown')
        if cat not in categories:
            categories[cat] = {'count': 0, 'sum': 0}
        categories[cat]['count'] += 1
        categories[cat]['sum'] += row.get('amount', 0)
    return {
        'id': report_id,
        'timestamp': timestamp,
        'total': total,
        'average': avg,
        'categories': categories,
        'config': config,
    }
